#include <stdio.h>
#include <stdlib.h>
#define MAXN 200005
#define MAXM 5000005

// Define the structure for a graph edge
typedef struct Edge {
    int u, v;
} Edge;

// Define the structure for a graph
typedef struct Graph {
    int n, m;
    Edge *edges;
} Graph;

// Function to read input and build the graph
Graph readInput() {
    Graph g;
    scanf("%d %d", &g.n, &g.m);
    g.edges = (Edge *)malloc(g.m * sizeof(Edge));
    for (int i = 0; i < g.m; i++) {
        scanf("%d %d", &g.edges[i].u, &g.edges[i].v);
    }
    return g;
}

// Function to perform DFS and count paths
void dfs(Graph g, int u, int parent, int *low, int *disc, int *time, int *pathCount) {
    static int time = 0;
    disc[u] = low[u] = time++;
    for (int i = 0; i < g.m; i++) {
        if (g.edges[i].u == u) {
            int v = g.edges[i].v;
            if (disc[v] == -1) {
                dfs(g, v, u, low, disc, time, pathCount);
                low[u] = min(low[u], low[v]);
                if (low[v] > disc[u]) {
                    // Edge i is a bridge, increment path count
                    pathCount[i]++;
                }
            } else if (v != parent) {
                low[u] = min(low[u], disc[v]);
            }
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        Graph g = readInput();
        int *low = (int *)malloc(g.n * sizeof(int));
        int *disc = (int *)malloc(g.n * sizeof(int));
        int *pathCount = (int *)malloc(g.m * sizeof(int));
        for (int i = 0; i < g.n; i++) {
            disc[i] = -1;
        }
        for (int i = 0; i < g.m; i++) {
            pathCount[i] = 0;
        }
        for (int i = 0; i < g.n; i++) {
            if (disc[i] == -1) {
                dfs(g, i, -1, low, disc, 0, pathCount);
            }
        }
        for (int i = 0; i < g.m; i++) {
            printf("%d\n", pathCount[i]);
        }
        free(low);
        free(disc);
        free(pathCount);
        free(g.edges);
    }
    return 0;
}

